export interface BulkEinvoiceRequest {
  /**
     * @minItems 1
     * @maxItems 200
     */
  orderIds: number[];
}

/**
 * Lifecycle of one row inside a bulk batch.
 * - `pending`: classified as eligible, the worker has not
 *   reached it yet.
 * - `running`: the worker is mid-flight on this row.
 * - `success`: IRP accepted the invoice on this attempt.
 * - `already_issued`: an active IRN already existed before
 *   the batch started; nothing was re-attempted (this is
 *   what makes the bulk action idempotent on retry).
 * - `ineligible`: the order can never be processed in this
 *   batch (wrong status, missing buyer GSTIN, etc.).
 * - `failed`: the IRP rejected this attempt; the operator
 *   can re-run the batch on just the failures.
 * - `skipped`: another in-flight attempt held the claim, or
 *   the IRN was previously cancelled at the IRP.
 */
export type BulkEinvoiceResultRowStatus = typeof BulkEinvoiceResultRowStatus[keyof typeof BulkEinvoiceResultRowStatus];


export const BulkEinvoiceResultRowStatus = {
  pending: 'pending',
  running: 'running',
  success: 'success',
  already_issued: 'already_issued',
  ineligible: 'ineligible',
  failed: 'failed',
  skipped: 'skipped',
} as const;

export interface BulkEinvoiceResultRow {
  orderId: number;
  /** @nullable */
  orderNumber: string | null;
  /**
     * Lifecycle of one row inside a bulk batch.
     * - `pending`: classified as eligible, the worker has not
     *   reached it yet.
     * - `running`: the worker is mid-flight on this row.
     * - `success`: IRP accepted the invoice on this attempt.
     * - `already_issued`: an active IRN already existed before
     *   the batch started; nothing was re-attempted (this is
     *   what makes the bulk action idempotent on retry).
     * - `ineligible`: the order can never be processed in this
     *   batch (wrong status, missing buyer GSTIN, etc.).
     * - `failed`: the IRP rejected this attempt; the operator
     *   can re-run the batch on just the failures.
     * - `skipped`: another in-flight attempt held the claim, or
     *   the IRN was previously cancelled at the IRP.
     */
  status: BulkEinvoiceResultRowStatus;
  /** @nullable */
  message: string | null;
  /** @nullable */
  errorCode: string | null;
  /**
     * IRP-issued Invoice Reference Number for rows that ended
     * as `success` or `already_issued`. Null on every other
     * status. Carrying the IRN in its own field (rather than
     * forcing the UI to parse it out of the message) means the
     * CSV export can show the existing IRN even on rows that
     * were already registered before this batch began.
     * @nullable
     */
  irn: string | null;
  /**
     * IRP acknowledgement number that pairs with `irn`. Null
     * on rows that did not receive (or already had) an IRN.
     * @nullable
     */
  ackNumber: string | null;
  /**
     * ISO timestamp the IRN was acknowledged at the IRP. Null
     * on rows that did not receive (or already had) an IRN.
     * @nullable
     */
  ackDate: string | null;
}

export type BulkEinvoiceBatchStatus = typeof BulkEinvoiceBatchStatus[keyof typeof BulkEinvoiceBatchStatus];


export const BulkEinvoiceBatchStatus = {
  running: 'running',
  completed: 'completed',
} as const;

export interface BulkEinvoiceBatch {
  id: string;
  status: BulkEinvoiceBatchStatus;
  createdAt: string;
  /**
     * Wall-clock instant the worker began processing this batch.
     * For freshly-queued batches this equals `createdAt`; the
     * two columns diverge only if a future scheduling layer
     * queues batches before the worker picks them up.
     */
  startedAt: string;
  /** @nullable */
  completedAt: string | null;
  /**
     * Wall-clock milliseconds between `startedAt` and
     * `completedAt`. Null while the batch is still running so
     * partial numbers can't be mistaken for the final tally.
     * @nullable
     */
  durationMs: number | null;
  /**
     * Achieved throughput (`processed / durationSeconds`,
     * rounded to 1 decimal). Null while the batch is still
     * running. Lets operators verify the bulk concurrency
     * knob is actually delivering speedup against their IRP.
     * @nullable
     */
  ordersPerSecond: number | null;
  /**
     * Effective in-process worker fan-out the batch ran with —
     * the BULK_CONCURRENCY env value clamped against the
     * number of eligible orders.
     */
  concurrency: number;
  total: number;
  processed: number;
  /** Rows that finished as `success` or `already_issued`. */
  succeeded: number;
  /** Rows that finished as `failed`. */
  failed: number;
  /** Rows that finished as `skipped` or `ineligible`. */
  skipped: number;
  results: BulkEinvoiceResultRow[];
}

